<?php
declare(strict_types=1);
namespace Oasebos\Participations\Frontend;
use Oasebos\Participations\Database\Repository;
use Oasebos\Participations\Security\Nonces;
final class Shortcodes { private Repository $repo; public function __construct(){ $this->repo=new Repository(); } public function register(): void { add_shortcode('oasebos_participation_landing',[$this,'participationLanding']); add_shortcode('oasebos_participation_form',[$this,'participation']); add_shortcode('oasebos_donation_form',[$this,'donation']); add_shortcode('oasebos_payment_return',fn()=>'<div class="oasebos-message">'.esc_html__('Bedankt. De betaalstatus wordt door de betaalprovider verwerkt; de bevestiging volgt per e-mail.','oasebos-participations').'</div>'); } public function participationLanding($atts=[]): string { $atts=shortcode_atts(['form_page_url'=>'','button_label'=>__('Koop participatie','oasebos-participations')],$atts,'oasebos_participation_landing'); $projects=$this->repo->list('projects',['status'=>'active','limit'=>100]); $formPageUrl=$atts['form_page_url']?esc_url_raw((string)$atts['form_page_url']):''; if(! $formPageUrl){$formPageUrl=get_permalink()?:home_url('/participeren/');} ob_start(); include OASEBOS_PARTICIPATIONS_DIR.'templates/frontend/participation-landing.php'; $landing=ob_get_clean(); if(isset($_GET['basket'])||isset($_GET['project_id'])){return $this->participation(['show_project_selector'=>'false']);} return $landing; } public function participation($atts=[]): string { $atts=shortcode_atts(['project_id'=>0,'project_slug'=>'','show_project_selector'=>'true'],$atts,'oasebos_participation_form'); $projects=$this->repo->list('projects',['status'=>'active','limit'=>100]); $basketItems=[]; $basketParam=isset($_GET['basket'])?sanitize_text_field(wp_unslash((string)$_GET['basket'])):''; foreach(array_filter(array_map('trim',explode(',',$basketParam))) as $part){ [$rawProjectId,$rawUnits]=array_pad(explode(':',$part,2),2,'1'); $projectId=absint($rawProjectId); if($projectId>0){$basketItems[$projectId]=max(1,absint($rawUnits));} } if((int)$atts['project_id']>0){ $locked=$this->repo->get('projects',(int)$atts['project_id']); $projects=($locked&&$locked['status']==='active')?[$locked]:[]; } elseif($atts['project_slug']) { $locked=$this->repo->findBy('projects','slug',sanitize_title($atts['project_slug'])); $projects=($locked&&$locked['status']==='active')?[$locked]:[]; } $basketProjectId=isset($_GET['project_id'])?absint($_GET['project_id']):0; $basketUnits=isset($_GET['units'])?max(1,absint($_GET['units'])):1; if($basketProjectId>0){$basketItems=[$basketProjectId=>$basketUnits];} if($basketItems){$filtered=[]; foreach($basketItems as $projectId=>$units){$locked=$this->repo->get('projects',$projectId); if($locked&&$locked['status']==='active'){$locked['_basket_units']=$units;$filtered[]=$locked;}} $projects=$filtered;} elseif($basketProjectId>0){ $locked=$this->repo->get('projects',$basketProjectId); $projects=($locked&&$locked['status']==='active')?[$locked]:[]; } $showProjectSelector=($atts['show_project_selector']!=='false') && count($projects)>1 && ! $basketItems && $basketProjectId<=0; ob_start(); include OASEBOS_PARTICIPATIONS_DIR.'templates/frontend/participation-form.php'; return ob_get_clean(); } public function donation($atts=[]): string { $amounts=isset($atts['amounts'])?array_map('trim',explode(',',$atts['amounts'])):[2.50,5,10,15,20,25,50,75,100,150,200,250]; ob_start(); include OASEBOS_PARTICIPATIONS_DIR.'templates/frontend/donation-form.php'; return ob_get_clean(); } }
